Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** — it hosts your app in-memory and gives you an `HttpClient` that speaks to it without opening a real port.

```csharp
// McpIntegrationTests.cs
using Microsoft.AspNetCore.Mvc.Testing;
using System.Net.Http.Json;
using System.Text.Json;

public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.True(body.TryGetProperty("result", out var result));
        Assert.True(result.TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize first
        await InitializeSession();

        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };
        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    private async Task InitializeSession()
    {
        var init = new
        {
            jsonrpc = "2.0", id = 0, method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };
        await _client.PostAsJsonAsync("/mcp", init);
    }
}
```

**Key points:**

- **`WebApplicationFactory<Program>`** boots your full middleware pipeline (auth, routing, MCP handling) in-process — no port, no real server
- Replace `"/mcp"` with whatever your MCP endpoint path is
- If your server uses **SSE streaming**, read the response stream directly via `response.Content.ReadAsStreamAsync()` and parse `text/event-stream` lines
- Override services (e.g., mock a database) via `factory.WithWebHostBuilder(b => b.ConfigureServices(...))`
- Make sure `Program` is accessible — add `public partial class Program { }` to your entry point if needed

Add the test project dependency:

```bash
dotnet add reference ../YourMcpServer/YourMcpServer.csproj
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```
